BEGIN
  IF AD_isTriggerEnabled()='N' THEN RETURN;
  END IF;
	-- Verifica si existen líneas relacionadas
	  IF EXISTS (
		  SELECT 1
		  FROM scft_finan_acct_ind
		  WHERE scft_paramacct_id = :OLD.scft_paramacct_id
		) THEN
		  RAISE_APPLICATION_ERROR(-20000, '@scft_countrow_trg@');
		END IF;

END SCFT_FINACCT_COUNT_TRG
